// // This module implements a logic circuit that produces a LOW output (0) when either both inputs A1 and A2 are HIGH or both inputs B1 and C1 are HIGH; otherwise, it outputs a HIGH (1).
module top_module(
    input A1,
    input A2,
    input B1,
    input C1,
    output reg X
);always @(*) begin
        if ((A1 & A2) || (B1 & C1))
            X = 1;
        else
            X = 0;
    end

endmodule
